const page = document.body.dataset.page;
const nav = document.querySelectorAll('.site-nav a[data-nav]');
nav.forEach(a => { if (a.dataset.nav === page) a.classList.add('active'); });
const menuToggle = document.querySelector('.menu-toggle');
const navMenu = document.getElementById('site-nav');
if (menuToggle && navMenu) {
  menuToggle.addEventListener('click', () => {
    const open = navMenu.classList.toggle('open');
    menuToggle.setAttribute('aria-expanded', open ? 'true' : 'false');
  });
}
function applyTranslations(lang) {
  const t = translations[lang] || translations.en;
  document.documentElement.lang = lang === 'ar' ? 'ar' : lang;
  document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (t[key] !== undefined) el.innerHTML = t[key];
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.dataset.i18nPlaceholder;
    if (t[key] !== undefined) el.setAttribute('placeholder', t[key]);
  });
  const switcher = document.getElementById('lang-switcher');
  if (switcher) switcher.value = lang;
  localStorage.setItem('abaynex_lang', lang);
}
const switcher = document.getElementById('lang-switcher');
const savedLang = localStorage.getItem('abaynex_lang') || 'en';
applyTranslations(savedLang);
if (switcher) {
  switcher.addEventListener('change', e => applyTranslations(e.target.value));
}
